    27→export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
    28→  value,
    29→  onChange,
    30→  onClose,
    31→}) => {
    32→  // Local state (synced with value prop)
    33→  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    34→    value?.frequency || 'weekly'
    35→  );
    36→  const [interval, setInterval] = useState<number>(value?.interval || 1);
    37→  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
    38→  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
