    41→  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
    42→  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
    43→  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
