    45→  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
    46→  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);
    47→
    48→  // Natural language input state
