    64→      setDayOfMonth(value.dayOfMonth);
    65→      setWeekOfMonth(value.weekOfMonth);
    66→      setDayOfWeekInMonth(value.dayOfWeekInMonth);
    67→      // Set monthlyMode based on which fields are present
    68→      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
    69→        setMonthlyMode('ordinal');
    70→      } else {
