    73→      setEndType(value.endType);
    74→      setEndCount(value.endCount);
    75→      setEndDate(value.endDate);
    76→      setRecurFromCompletion(value.recurFromCompletion || false);
    77→      setTemplateId(value.templateId);
    78→    }
    79→  }, [value]);
    80→
    81→  // Helper: Parse natural language input
    82→  const handleParseNaturalLanguage = () => {
    83→    if (!naturalInput.trim()) {
    84→      setParseError(null);
    85→      return;
    86→    }
    87→
    88→    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    89→    if (parsed) {
    90→      // Auto-fill fields from parsed rule
    91→      setFrequency(parsed.frequency);
    92→      if (parsed.interval !== undefined) setInterval(parsed.interval);
    93→      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
    94→      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
    95→      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
    96→      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
    97→      // Set monthlyMode based on which fields are present
    98→      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
    99→        setMonthlyMode('ordinal');
   100→      } else if (parsed.dayOfMonth !== undefined) {
   101→        setMonthlyMode('day');
   102→      }
   103→      setEndType(parsed.endType);
   104→      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
   105→      if (parsed.endDate) setEndDate(parsed.endDate);
   106→      setParseError(null);
