   141→        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
   142→        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
   143→      } else if (dayOfMonth) {
