}: NaturalLanguageDateInputProps) {
  const [inputValue, setInputValue] = useState(''); // Internal NL input state
  const [parsedDate, setParsedDate] = useState<Date | null>(null);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [highlightedIndex, setHighlightedIndex] = useState(0);
  const [isInvalid, setIsInvalid] = useState(false);
  const [debounceTimeout, setDebounceTimeout] = useState<NodeJS.Timeout | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const componentId = useRef(`nl-date-input-${Math.random().toString(36).substr(2, 9)}`).current;

  // Keyboard shortcuts (@tomorrow, +3d, etc.)
  useInlineDateShortcuts(inputRef, onChange);

  // Sync with external value changes (controlled component)
  useEffect(() => {
    if (value && value !== format(parsedDate || new Date(0), 'yyyy-MM-dd')) {
      try {
        const date = new Date(value);
        if (!isNaN(date.getTime())) {
          setParsedDate(date);
          // Don't update inputValue - let user keep their NL text
        }
      } catch {
        // Invalid date format
      }
    } else if (!value) {
      // Value cleared externally
      setInputValue('');
      setParsedDate(null);
      setIsInvalid(false);
    }
  }, [value, parsedDate]);

  // Get suggestions
  const allSuggestions = useMemo(() => getSmartDateSuggestions(), []);

  // Filter suggestions based on input
  const filteredSuggestions = useMemo(() => {
    return filterSuggestions(allSuggestions, inputValue);
  }, [allSuggestions, inputValue]);

  // Parse input with debounce (150ms)
  const parseInput = useCallback((text: string) => {
    if (debounceTimeout) {
      clearTimeout(debounceTimeout);
    }

    const timeout = setTimeout(() => {
      if (!text.trim()) {
        setParsedDate(null);
        setIsInvalid(false);
        onChange(null);
        return;
      }

      const parsed = parseNaturalLanguageDate(text);
      if (parsed) {
        setParsedDate(parsed);
        setIsInvalid(false);
        // Convert to YYYY-MM-DD format
        const formattedDate = format(parsed, 'yyyy-MM-dd');
        onChange(formattedDate);
      } else {
        setParsedDate(null);
        setIsInvalid(text.length > 0);
        onChange(null);
      }
    }, 150);

    setDebounceTimeout(timeout);
  }, [onChange, debounceTimeout]);

  // Handle input change
  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setInputValue(newValue);
    parseInput(newValue);
    setShowSuggestions(true);
    setHighlightedIndex(0);
  }, [parseInput]);

  // Handle suggestion click
  const handleSuggestionClick = useCallback((suggestion: DateSuggestion) => {
    if (suggestion.label === 'Custom') {
      // Focus input for custom entry
      inputRef.current?.focus();
      return;
    }

    setInputValue(suggestion.nlText);
    setParsedDate(suggestion.date);
    setIsInvalid(false);
    setShowSuggestions(false);

    // Convert to YYYY-MM-DD format
    const formattedDate = format(suggestion.date, 'yyyy-MM-dd');
    onChange(formattedDate);
  }, [onChange]);

  // Handle keyboard navigation
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (!showSuggestions) {
      // Show suggestions on arrow down
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setShowSuggestions(true);
        setHighlightedIndex(0);
      }
      return;
    }

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setHighlightedIndex((prev) =>
          prev < filteredSuggestions.length - 1 ? prev + 1 : 0
        );
        break;

      case 'ArrowUp':
        e.preventDefault();
        setHighlightedIndex((prev) =>
          prev > 0 ? prev - 1 : filteredSuggestions.length - 1
        );
        break;

      case 'Enter':
        e.preventDefault();
        if (filteredSuggestions[highlightedIndex]) {
          handleSuggestionClick(filteredSuggestions[highlightedIndex]);
        }
        break;

      case 'Escape':
        e.preventDefault();
        setShowSuggestions(false);
        setInputValue('');
        setParsedDate(null);
        setIsInvalid(false);
        onChange(null);
        break;

      case 'Tab':
        // Accept current parse or move to next field
        setShowSuggestions(false);
        break;

      default:
        break;
    }
  }, [showSuggestions, filteredSuggestions, highlightedIndex, handleSuggestionClick, onChange]);

  // Handle clear
  const handleClear = useCallback(() => {
    setInputValue('');
    setParsedDate(null);
    setIsInvalid(false);
    setShowSuggestions(false);
    onChange(null);
    inputRef.current?.focus();
  }, [onChange]);

  // Handle click outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node) &&
        inputRef.current &&
        !inputRef.current.contains(event.target as Node)
      ) {
        setShowSuggestions(false);
      }
    }

    if (showSuggestions) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [showSuggestions]);

  // Keyboard shortcut: Cmd/Ctrl+K to clear
  useEffect(() => {
    function handleGlobalKeyDown(e: KeyboardEvent) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k' && document.activeElement === inputRef.current) {
        e.preventDefault();
        handleClear();
      }
    }

    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [handleClear]);

  // Auto-focus if requested
  useEffect(() => {
    if (autoFocus && inputRef.current) {
      inputRef.current.focus();
    }
  }, [autoFocus]);

  // Scroll highlighted item into view
  useEffect(() => {
    if (showSuggestions && dropdownRef.current) {
      const highlightedElement = dropdownRef.current.querySelector(
        `[data-index="${highlightedIndex}"]`
      );
      if (highlightedElement) {
        highlightedElement.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
      }
    }
  }, [highlightedIndex, showSuggestions]);

  return (
    <div className={`relative ${className}`}>
      {/* Label */}
      {label && (
        <label
          htmlFor={componentId}
          className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
        >
          {label}
        </label>
      )}

      {/* Input */}
      <div className="relative">
        <input
          ref={inputRef}
          id={componentId}
          type="text"
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={() => setShowSuggestions(true)}
          placeholder={placeholder}
          disabled={disabled}
          className={`w-full px-2.5 py-1.5 pr-8 text-xs border rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-secondary dark:placeholder:text-text-dark-secondary focus:outline-none focus:ring-2 transition-colors ${
            isInvalid
              ? 'border-accent-red focus:ring-accent-red'
              : 'border-border-light dark:border-border-dark focus:ring-accent-blue'
          }`}
          aria-label={label || 'Date input'}
          aria-describedby={`${componentId}-preview`}
          aria-invalid={isInvalid}
          aria-autocomplete="list"
          aria-controls={`${componentId}-suggestions`}
          aria-expanded={showSuggestions}
          role="combobox"
        />

        {/* Clear button */}
        {inputValue && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-0.5 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
            aria-label="Clear date"
          >
            <X className="w-3.5 h-3.5 text-text-light-secondary dark:text-text-dark-secondary" />
          </button>
        )}
      </div>

      {/* Parsed date preview */}
      {parsedDate && !isInvalid && (
        <div
          id={`${componentId}-preview`}
          className="mt-1 text-[10px] text-accent-green dark:text-accent-green"
        >
          → {formatDateForDisplay(parsedDate)}
        </div>
      )}

      {/* Error message */}
      {isInvalid && inputValue && (
        <div
          id={`${componentId}-preview`}
          className="mt-1 text-[10px] text-accent-red dark:text-accent-red"
        >
          Could not parse date
        </div>
      )}

      {/* Suggestions dropdown */}
      {showSuggestions && !disabled && filteredSuggestions.length > 0 && (
        <div
          ref={dropdownRef}
          id={`${componentId}-suggestions`}
          role="listbox"
          aria-label="Date suggestions"
          className="absolute z-50 w-full mt-1 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg shadow-lg max-h-60 overflow-y-auto"
        >
          {filteredSuggestions.map((suggestion, index) => {
            const isHighlighted = index === highlightedIndex;
            const display = formatSuggestionDisplay(suggestion);

            return (
              <button
                key={`${suggestion.label}-${index}`}
                type="button"
                data-index={index}
                role="option"
                aria-selected={isHighlighted}
                onClick={() => handleSuggestionClick(suggestion)}
                className={`w-full text-left px-3 py-2 text-xs transition-colors ${
                  isHighlighted
                    ? 'bg-accent-blue/10 text-accent-blue'
                    : 'text-text-light-primary dark:text-text-dark-primary hover:bg-surface-light-elevated dark:hover:bg-neutral-800'
                }`}
              >
                {display}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import type { Task } from '../types';
import { parseRecurrenceNaturalLanguage } from '../utils/naturalLanguageRecurrence';
import { TemplatePicker } from './TemplatePicker';
import { useTemplateStore } from '../stores/useTemplateStore';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface RecurrencePickerProps {
  value: Task['recurrence'];
  onChange: (recurrence: Task['recurrence']) => void;
  onClose?: () => void;
}

/**
 * RecurrencePicker Component
 * UI for setting up recurring task patterns
 *
 * Features:
 * - Frequency selection (daily, weekly, monthly, yearly)
 * - Interval input (every X days/weeks/months/years)
 * - Day of week picker (for weekly)
 * - Day of month picker (for monthly)
 * - End condition (never, after X occurrences, until date)
 * - Clear visual feedback
 * - Matches Calendar event recurrence UI patterns
 */
export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
  value,
  onChange,
  onClose,
}) => {
  // Local state (synced with value prop)
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    value?.frequency || 'weekly'
  );
  const [interval, setInterval] = useState<number>(value?.interval || 1);
  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
  const [weekOfMonth, setWeekOfMonth] = useState<1 | 2 | 3 | 4 | -1 | undefined>(value?.weekOfMonth);
  const [dayOfWeekInMonth, setDayOfWeekInMonth] = useState<number | undefined>(value?.dayOfWeekInMonth);
  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);

  // Natural language input state
  const [naturalInput, setNaturalInput] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Advanced section toggle
  const [showAdvanced, setShowAdvanced] = useState<boolean>(false);

  // Template store
  const { templates } = useTemplateStore();

  // Sync local state with value prop when it changes
  useEffect(() => {
    if (value) {
      setFrequency(value.frequency);
      setInterval(value.interval);
      setDaysOfWeek(value.daysOfWeek || []);
      setDayOfMonth(value.dayOfMonth);
      setWeekOfMonth(value.weekOfMonth);
      setDayOfWeekInMonth(value.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else {
        setMonthlyMode('day');
      }
      setEndType(value.endType);
      setEndCount(value.endCount);
      setEndDate(value.endDate);
      setRecurFromCompletion(value.recurFromCompletion || false);
      setTemplateId(value.templateId);
    }
  }, [value]);

  // Helper: Parse natural language input
  const handleParseNaturalLanguage = () => {
    if (!naturalInput.trim()) {
      setParseError(null);
      return;
    }

    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    if (parsed) {
      // Auto-fill fields from parsed rule
      setFrequency(parsed.frequency);
      if (parsed.interval !== undefined) setInterval(parsed.interval);
      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else if (parsed.dayOfMonth !== undefined) {
        setMonthlyMode('day');
      }
      setEndType(parsed.endType);
      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
      if (parsed.endDate) setEndDate(parsed.endDate);
      setParseError(null);
    } else {
      setParseError('Could not parse input. Try "every 2 weeks on Monday"');
    }
  };

  // Helper: Toggle day of week selection
  const toggleDayOfWeek = (day: number) => {
    setDaysOfWeek((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    );
  };

  // Helper: Build recurrence summary text
  const getRecurrenceSummary = (): string => {
    let summary = 'Repeats ';

    // Frequency and interval
    if (interval === 1) {
      summary += frequency;
    } else {
      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    }

    // Days of week (for weekly)
    if (frequency === 'weekly' && daysOfWeek.length > 0) {
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
      summary += ` on ${selectedDays}`;
    }

    // Day of month or ordinal pattern (for monthly)
    if (frequency === 'monthly') {
      if (weekOfMonth !== undefined && dayOfWeekInMonth !== undefined) {
        const ordinalStr = { '1': 'first', '2': 'second', '3': 'third', '4': 'fourth', '-1': 'last' }[weekOfMonth.toString()];
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
      } else if (dayOfMonth) {
        summary += ` on day ${dayOfMonth}`;
      }
    }

    // End condition
    if (endType === 'after' && endCount) {
      summary += `, ends after ${endCount} occurrences`;
    } else if (endType === 'until' && endDate) {
      summary += `, ends on ${endDate}`;
    }

    return summary;
  };

  // Save recurrence and call onChange
  const handleSave = () => {
    const recurrence: Task['recurrence'] = {
      frequency,
      interval,
      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
      dayOfMonth: frequency === 'monthly' && monthlyMode === 'day' ? dayOfMonth : undefined,
      weekOfMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? weekOfMonth : undefined,
      dayOfWeekInMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? dayOfWeekInMonth : undefined,
      endType,
      endCount: endType === 'after' ? endCount : undefined,
      endDate: endType === 'until' ? endDate : undefined,
      recurFromCompletion,
      templateId,
    };

    onChange(recurrence);
    if (onClose) onClose();
  };

  // Clear recurrence
  const handleClear = () => {
    onChange(undefined);
    if (onClose) onClose();
  };

  return (
    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
          Set Recurrence
        </h3>
        {value && (
          <button
            onClick={handleClear}
            className="text-xs text-red-500 hover:text-red-600 dark:text-red-400 dark:hover:text-red-300"
          >
            Clear
          </button>
        )}
      </div>

      {/* Natural Language Input (Quick Setup) */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Quick Setup (optional)
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            value={naturalInput}
            onChange={(e) => setNaturalInput(e.target.value)}
            onBlur={handleParseNaturalLanguage}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleParseNaturalLanguage();
              }
            }}
            placeholder="e.g., every 2 weeks on Monday"
            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          {naturalInput && (
            <button
              onClick={() => {
                setNaturalInput('');
                setParseError(null);
              }}
              className="px-3 py-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Clear
            </button>
          )}
        </div>
        {parseError && (
          <p className="text-xs text-red-600 dark:text-red-400 mt-1">{parseError}</p>
        )}
        {naturalInput && !parseError && (
          <p className="text-xs text-green-600 dark:text-green-400 mt-1">
            ✓ Parsed successfully
          </p>
        )}
      </div>

      {/* Frequency */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Frequency
        </label>
        <select
          value={frequency}
          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
        >
          <option value="daily">Daily</option>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>
      </div>

      {/* Interval */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Repeat every
        </label>
        <div className="flex items-center gap-2">
          <input
            type="number"
            min="1"
            max="999"
            value={interval}
            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
          </span>
        </div>
      </div>

      {/* Days of Week (for weekly) */}
      {frequency === 'weekly' && (
        <div>
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
            Repeat on
          </label>
          <div className="flex gap-2">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
              <button
                key={day}
                onClick={() => toggleDayOfWeek(index)}
                className={`
                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
                  ${
                    daysOfWeek.includes(index)
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-700'
                  }
                `}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Monthly Pattern Selection */}
      {frequency === 'monthly' && (
        <div className="space-y-3">
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
            Repeat on
          </label>

          {/* Option 1: Specific day of month */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'day'}
              onChange={() => setMonthlyMode('day')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Day</span>
            <input
              type="number"
              min="1"
              max="31"
              value={dayOfMonth || ''}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
                setMonthlyMode('day');
              }}
              placeholder="1-31"
              disabled={monthlyMode !== 'day'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>

          {/* Option 2: Ordinal pattern (first Monday, last Friday, etc.) */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'ordinal'}
              onChange={() => setMonthlyMode('ordinal')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">The</span>
            <select
              value={weekOfMonth || 1}
              onChange={(e) => {
                setWeekOfMonth(parseInt(e.target.value) as 1 | 2 | 3 | 4 | -1);
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={1}>first</option>
              <option value={2}>second</option>
              <option value={3}>third</option>
              <option value={4}>fourth</option>
              <option value={-1}>last</option>
            </select>
            <select
              value={dayOfWeekInMonth !== undefined ? dayOfWeekInMonth : 1}
              onChange={(e) => {
                setDayOfWeekInMonth(parseInt(e.target.value));
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={0}>Sunday</option>
              <option value={1}>Monday</option>
              <option value={2}>Tuesday</option>
              <option value={3}>Wednesday</option>
              <option value={4}>Thursday</option>
              <option value={5}>Friday</option>
              <option value={6}>Saturday</option>
            </select>
          </label>
        </div>
      )}

      {/* Recur from Completion Date */}
      <div>
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={recurFromCompletion}
            onChange={(e) => setRecurFromCompletion(e.target.checked)}
            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
          />
          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
            Recur from completion date
          </span>
        </label>
        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
        </p>
      </div>

      {/* End Condition */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Ends
        </label>
        <div className="space-y-3">
          {/* Never */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'never'}
              onChange={() => setEndType('never')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
          </label>

          {/* After X occurrences */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'after'}
              onChange={() => setEndType('after')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
            <input
              type="number"
              min="1"
              max="999"
              value={endCount || ''}
              onChange={(e) => {
                setEndType('after');
                setEndCount(Math.max(1, parseInt(e.target.value) || 1));
              }}
              disabled={endType !== 'after'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">occurrences</span>
          </label>

          {/* Until date */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'until'}
              onChange={() => setEndType('until')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">On</span>
            <input
              type="date"
              value={endDate || ''}
              onChange={(e) => {
                setEndType('until');
                setEndDate(e.target.value);
              }}
              disabled={endType !== 'until'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>
        </div>
      </div>

      {/* Advanced Section */}
      <div>
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex items-center gap-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
        >
          {showAdvanced ? (
            <ChevronDown className="w-4 h-4" />
          ) : (
            <ChevronRight className="w-4 h-4" />
          )}
          Advanced
        </button>
        {showAdvanced && (
          <div className="mt-3 space-y-3 pl-6">
            <TemplatePicker
              value={templateId}
              onChange={setTemplateId}
              templates={templates}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
        <p className="text-xs text-text-light-primary dark:text-text-dark-primary">
          {getRecurrenceSummary()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className="flex-1 py-2 px-4 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue/90 transition-colors"
        >
          Save
        </button>
        {onClose && (
          <button
            onClick={onClose}
            className="py-2 px-4 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary text-sm font-medium rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import type { Task } from '../types';
import { parseRecurrenceNaturalLanguage } from '../utils/naturalLanguageRecurrence';
import { TemplatePicker } from './TemplatePicker';
import { useTemplateStore } from '../stores/useTemplateStore';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface RecurrencePickerProps {
  value: Task['recurrence'];
  onChange: (recurrence: Task['recurrence']) => void;
  onClose?: () => void;
}

/**
 * RecurrencePicker Component
 * UI for setting up recurring task patterns
 *
 * Features:
 * - Frequency selection (daily, weekly, monthly, yearly)
 * - Interval input (every X days/weeks/months/years)
 * - Day of week picker (for weekly)
 * - Day of month picker (for monthly)
 * - End condition (never, after X occurrences, until date)
 * - Clear visual feedback
 * - Matches Calendar event recurrence UI patterns
 */
export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
  value,
  onChange,
  onClose,
}) => {
  // Local state (synced with value prop)
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    value?.frequency || 'weekly'
  );
  const [interval, setInterval] = useState<number>(value?.interval || 1);
  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
  const [weekOfMonth, setWeekOfMonth] = useState<1 | 2 | 3 | 4 | -1 | undefined>(value?.weekOfMonth);
  const [dayOfWeekInMonth, setDayOfWeekInMonth] = useState<number | undefined>(value?.dayOfWeekInMonth);
  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);

  // Natural language input state
  const [naturalInput, setNaturalInput] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Advanced section toggle
  const [showAdvanced, setShowAdvanced] = useState<boolean>(false);

  // Template store
  const { templates } = useTemplateStore();

  // Sync local state with value prop when it changes
  useEffect(() => {
    if (value) {
      setFrequency(value.frequency);
      setInterval(value.interval);
      setDaysOfWeek(value.daysOfWeek || []);
      setDayOfMonth(value.dayOfMonth);
      setWeekOfMonth(value.weekOfMonth);
      setDayOfWeekInMonth(value.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else {
        setMonthlyMode('day');
      }
      setEndType(value.endType);
      setEndCount(value.endCount);
      setEndDate(value.endDate);
      setRecurFromCompletion(value.recurFromCompletion || false);
      setTemplateId(value.templateId);
    }
  }, [value]);

  // Helper: Parse natural language input
  const handleParseNaturalLanguage = () => {
    if (!naturalInput.trim()) {
      setParseError(null);
      return;
    }

    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    if (parsed) {
      // Auto-fill fields from parsed rule
      setFrequency(parsed.frequency);
      if (parsed.interval !== undefined) setInterval(parsed.interval);
      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else if (parsed.dayOfMonth !== undefined) {
        setMonthlyMode('day');
      }
      setEndType(parsed.endType);
      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
      if (parsed.endDate) setEndDate(parsed.endDate);
      setParseError(null);
    } else {
      setParseError('Could not parse input. Try "every 2 weeks on Monday"');
    }
  };

  // Helper: Toggle day of week selection
  const toggleDayOfWeek = (day: number) => {
    setDaysOfWeek((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    );
  };

  // Helper: Build recurrence summary text
  const getRecurrenceSummary = (): string => {
    let summary = 'Repeats ';

    // Frequency and interval
    if (interval === 1) {
      summary += frequency;
    } else {
      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    }

    // Days of week (for weekly)
    if (frequency === 'weekly' && daysOfWeek.length > 0) {
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
      summary += ` on ${selectedDays}`;
    }

    // Day of month or ordinal pattern (for monthly)
    if (frequency === 'monthly') {
      if (weekOfMonth !== undefined && dayOfWeekInMonth !== undefined) {
        const ordinalStr = { '1': 'first', '2': 'second', '3': 'third', '4': 'fourth', '-1': 'last' }[weekOfMonth.toString()];
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
      } else if (dayOfMonth) {
        summary += ` on day ${dayOfMonth}`;
      }
    }

    // End condition
    if (endType === 'after' && endCount) {
      summary += `, ends after ${endCount} occurrences`;
    } else if (endType === 'until' && endDate) {
      summary += `, ends on ${endDate}`;
    }

    return summary;
  };

  // Save recurrence and call onChange
  const handleSave = () => {
    const recurrence: Task['recurrence'] = {
      frequency,
      interval,
      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
      dayOfMonth: frequency === 'monthly' && monthlyMode === 'day' ? dayOfMonth : undefined,
      weekOfMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? weekOfMonth : undefined,
      dayOfWeekInMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? dayOfWeekInMonth : undefined,
      endType,
      endCount: endType === 'after' ? endCount : undefined,
      endDate: endType === 'until' ? endDate : undefined,
      recurFromCompletion,
      templateId,
    };

    onChange(recurrence);
    if (onClose) onClose();
  };

  // Clear recurrence
  const handleClear = () => {
    onChange(undefined);
    if (onClose) onClose();
  };

  return (
    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
          Set Recurrence
        </h3>
        {value && (
          <button
            onClick={handleClear}
            className="text-xs text-accent-red hover:text-accent-red-hover dark:text-accent-red dark:hover:text-accent-red-hover"
          >
            Clear
          </button>
        )}
      </div>

      {/* Natural Language Input (Quick Setup) */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Quick Setup (optional)
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            value={naturalInput}
            onChange={(e) => setNaturalInput(e.target.value)}
            onBlur={handleParseNaturalLanguage}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleParseNaturalLanguage();
              }
            }}
            placeholder="e.g., every 2 weeks on Monday"
            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          {naturalInput && (
            <button
              onClick={() => {
                setNaturalInput('');
                setParseError(null);
              }}
              className="px-3 py-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Clear
            </button>
          )}
        </div>
        {parseError && (
          <p className="text-xs text-red-600 dark:text-red-400 mt-1">{parseError}</p>
        )}
        {naturalInput && !parseError && (
          <p className="text-xs text-green-600 dark:text-green-400 mt-1">
            ✓ Parsed successfully
          </p>
        )}
      </div>

      {/* Frequency */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Frequency
        </label>
        <select
          value={frequency}
          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
        >
          <option value="daily">Daily</option>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>
      </div>

      {/* Interval */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Repeat every
        </label>
        <div className="flex items-center gap-2">
          <input
            type="number"
            min="1"
            max="999"
            value={interval}
            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
          </span>
        </div>
      </div>

      {/* Days of Week (for weekly) */}
      {frequency === 'weekly' && (
        <div>
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
            Repeat on
          </label>
          <div className="flex gap-2">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
              <button
                key={day}
                onClick={() => toggleDayOfWeek(index)}
                className={`
                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
                  ${
                    daysOfWeek.includes(index)
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-700'
                  }
                `}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Monthly Pattern Selection */}
      {frequency === 'monthly' && (
        <div className="space-y-3">
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
            Repeat on
          </label>

          {/* Option 1: Specific day of month */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'day'}
              onChange={() => setMonthlyMode('day')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Day</span>
            <input
              type="number"
              min="1"
              max="31"
              value={dayOfMonth || ''}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
                setMonthlyMode('day');
              }}
              placeholder="1-31"
              disabled={monthlyMode !== 'day'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>

          {/* Option 2: Ordinal pattern (first Monday, last Friday, etc.) */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'ordinal'}
              onChange={() => setMonthlyMode('ordinal')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">The</span>
            <select
              value={weekOfMonth || 1}
              onChange={(e) => {
                setWeekOfMonth(parseInt(e.target.value) as 1 | 2 | 3 | 4 | -1);
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={1}>first</option>
              <option value={2}>second</option>
              <option value={3}>third</option>
              <option value={4}>fourth</option>
              <option value={-1}>last</option>
            </select>
            <select
              value={dayOfWeekInMonth !== undefined ? dayOfWeekInMonth : 1}
              onChange={(e) => {
                setDayOfWeekInMonth(parseInt(e.target.value));
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={0}>Sunday</option>
              <option value={1}>Monday</option>
              <option value={2}>Tuesday</option>
              <option value={3}>Wednesday</option>
              <option value={4}>Thursday</option>
              <option value={5}>Friday</option>
              <option value={6}>Saturday</option>
            </select>
          </label>
        </div>
      )}

      {/* Recur from Completion Date */}
      <div>
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={recurFromCompletion}
            onChange={(e) => setRecurFromCompletion(e.target.checked)}
            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
          />
          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
            Recur from completion date
          </span>
        </label>
        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
        </p>
      </div>

      {/* End Condition */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Ends
        </label>
        <div className="space-y-3">
          {/* Never */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'never'}
              onChange={() => setEndType('never')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
          </label>

          {/* After X occurrences */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'after'}
              onChange={() => setEndType('after')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
            <input
              type="number"
              min="1"
              max="999"
              value={endCount || ''}
              onChange={(e) => {
                setEndType('after');
                setEndCount(Math.max(1, parseInt(e.target.value) || 1));
              }}
              disabled={endType !== 'after'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">occurrences</span>
          </label>

          {/* Until date */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'until'}
              onChange={() => setEndType('until')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">On</span>
            <input
              type="date"
              value={endDate || ''}
              onChange={(e) => {
                setEndType('until');
                setEndDate(e.target.value);
              }}
              disabled={endType !== 'until'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>
        </div>
      </div>

      {/* Advanced Section */}
      <div>
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex items-center gap-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
        >
          {showAdvanced ? (
            <ChevronDown className="w-4 h-4" />
          ) : (
            <ChevronRight className="w-4 h-4" />
          )}
          Advanced
        </button>
        {showAdvanced && (
          <div className="mt-3 space-y-3 pl-6">
            <TemplatePicker
              value={templateId}
              onChange={setTemplateId}
              templates={templates}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
        <p className="text-xs text-text-light-primary dark:text-text-dark-primary">
          {getRecurrenceSummary()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className="flex-1 py-2 px-4 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue/90 transition-colors"
        >
          Save
        </button>
        {onClose && (
          <button
            onClick={onClose}
            className="py-2 px-4 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary text-sm font-medium rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import type { Task } from '../types';
import { parseRecurrenceNaturalLanguage } from '../utils/naturalLanguageRecurrence';
import { TemplatePicker } from './TemplatePicker';
import { useTemplateStore } from '../stores/useTemplateStore';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface RecurrencePickerProps {
  value: Task['recurrence'];
  onChange: (recurrence: Task['recurrence']) => void;
  onClose?: () => void;
}

/**
 * RecurrencePicker Component
 * UI for setting up recurring task patterns
 *
 * Features:
 * - Frequency selection (daily, weekly, monthly, yearly)
 * - Interval input (every X days/weeks/months/years)
 * - Day of week picker (for weekly)
 * - Day of month picker (for monthly)
 * - End condition (never, after X occurrences, until date)
 * - Clear visual feedback
 * - Matches Calendar event recurrence UI patterns
 */
export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
  value,
  onChange,
  onClose,
}) => {
  // Local state (synced with value prop)
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    value?.frequency || 'weekly'
  );
  const [interval, setInterval] = useState<number>(value?.interval || 1);
  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
  const [weekOfMonth, setWeekOfMonth] = useState<1 | 2 | 3 | 4 | -1 | undefined>(value?.weekOfMonth);
  const [dayOfWeekInMonth, setDayOfWeekInMonth] = useState<number | undefined>(value?.dayOfWeekInMonth);
  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);

  // Natural language input state
  const [naturalInput, setNaturalInput] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Advanced section toggle
  const [showAdvanced, setShowAdvanced] = useState<boolean>(false);

  // Template store
  const { templates } = useTemplateStore();

  // Sync local state with value prop when it changes
  useEffect(() => {
    if (value) {
      setFrequency(value.frequency);
      setInterval(value.interval);
      setDaysOfWeek(value.daysOfWeek || []);
      setDayOfMonth(value.dayOfMonth);
      setWeekOfMonth(value.weekOfMonth);
      setDayOfWeekInMonth(value.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else {
        setMonthlyMode('day');
      }
      setEndType(value.endType);
      setEndCount(value.endCount);
      setEndDate(value.endDate);
      setRecurFromCompletion(value.recurFromCompletion || false);
      setTemplateId(value.templateId);
    }
  }, [value]);

  // Helper: Parse natural language input
  const handleParseNaturalLanguage = () => {
    if (!naturalInput.trim()) {
      setParseError(null);
      return;
    }

    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    if (parsed) {
      // Auto-fill fields from parsed rule
      setFrequency(parsed.frequency);
      if (parsed.interval !== undefined) setInterval(parsed.interval);
      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else if (parsed.dayOfMonth !== undefined) {
        setMonthlyMode('day');
      }
      setEndType(parsed.endType);
      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
      if (parsed.endDate) setEndDate(parsed.endDate);
      setParseError(null);
    } else {
      setParseError('Could not parse input. Try "every 2 weeks on Monday"');
    }
  };

  // Helper: Toggle day of week selection
  const toggleDayOfWeek = (day: number) => {
    setDaysOfWeek((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    );
  };

  // Helper: Build recurrence summary text
  const getRecurrenceSummary = (): string => {
    let summary = 'Repeats ';

    // Frequency and interval
    if (interval === 1) {
      summary += frequency;
    } else {
      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    }

    // Days of week (for weekly)
    if (frequency === 'weekly' && daysOfWeek.length > 0) {
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
      summary += ` on ${selectedDays}`;
    }

    // Day of month or ordinal pattern (for monthly)
    if (frequency === 'monthly') {
      if (weekOfMonth !== undefined && dayOfWeekInMonth !== undefined) {
        const ordinalStr = { '1': 'first', '2': 'second', '3': 'third', '4': 'fourth', '-1': 'last' }[weekOfMonth.toString()];
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
      } else if (dayOfMonth) {
        summary += ` on day ${dayOfMonth}`;
      }
    }

    // End condition
    if (endType === 'after' && endCount) {
      summary += `, ends after ${endCount} occurrences`;
    } else if (endType === 'until' && endDate) {
      summary += `, ends on ${endDate}`;
    }

    return summary;
  };

  // Save recurrence and call onChange
  const handleSave = () => {
    const recurrence: Task['recurrence'] = {
      frequency,
      interval,
      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
      dayOfMonth: frequency === 'monthly' && monthlyMode === 'day' ? dayOfMonth : undefined,
      weekOfMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? weekOfMonth : undefined,
      dayOfWeekInMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? dayOfWeekInMonth : undefined,
      endType,
      endCount: endType === 'after' ? endCount : undefined,
      endDate: endType === 'until' ? endDate : undefined,
      recurFromCompletion,
      templateId,
    };

    onChange(recurrence);
    if (onClose) onClose();
  };

  // Clear recurrence
  const handleClear = () => {
    onChange(undefined);
    if (onClose) onClose();
  };

  return (
    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
          Set Recurrence
        </h3>
        {value && (
          <button
            onClick={handleClear}
            className="text-xs text-accent-red hover:text-accent-red-hover dark:text-accent-red dark:hover:text-accent-red-hover"
          >
            Clear
          </button>
        )}
      </div>

      {/* Natural Language Input (Quick Setup) */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Quick Setup (optional)
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            value={naturalInput}
            onChange={(e) => setNaturalInput(e.target.value)}
            onBlur={handleParseNaturalLanguage}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleParseNaturalLanguage();
              }
            }}
            placeholder="e.g., every 2 weeks on Monday"
            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          {naturalInput && (
            <button
              onClick={() => {
                setNaturalInput('');
                setParseError(null);
              }}
              className="px-3 py-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Clear
            </button>
          )}
        </div>
        {parseError && (
          <p className="text-xs text-accent-red dark:text-accent-red mt-1">{parseError}</p>
        )}
        {naturalInput && !parseError && (
          <p className="text-xs text-green-600 dark:text-green-400 mt-1">
            ✓ Parsed successfully
          </p>
        )}
      </div>

      {/* Frequency */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Frequency
        </label>
        <select
          value={frequency}
          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
        >
          <option value="daily">Daily</option>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>
      </div>

      {/* Interval */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Repeat every
        </label>
        <div className="flex items-center gap-2">
          <input
            type="number"
            min="1"
            max="999"
            value={interval}
            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
          </span>
        </div>
      </div>

      {/* Days of Week (for weekly) */}
      {frequency === 'weekly' && (
        <div>
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
            Repeat on
          </label>
          <div className="flex gap-2">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
              <button
                key={day}
                onClick={() => toggleDayOfWeek(index)}
                className={`
                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
                  ${
                    daysOfWeek.includes(index)
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-700'
                  }
                `}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Monthly Pattern Selection */}
      {frequency === 'monthly' && (
        <div className="space-y-3">
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
            Repeat on
          </label>

          {/* Option 1: Specific day of month */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'day'}
              onChange={() => setMonthlyMode('day')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Day</span>
            <input
              type="number"
              min="1"
              max="31"
              value={dayOfMonth || ''}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
                setMonthlyMode('day');
              }}
              placeholder="1-31"
              disabled={monthlyMode !== 'day'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>

          {/* Option 2: Ordinal pattern (first Monday, last Friday, etc.) */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'ordinal'}
              onChange={() => setMonthlyMode('ordinal')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">The</span>
            <select
              value={weekOfMonth || 1}
              onChange={(e) => {
                setWeekOfMonth(parseInt(e.target.value) as 1 | 2 | 3 | 4 | -1);
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={1}>first</option>
              <option value={2}>second</option>
              <option value={3}>third</option>
              <option value={4}>fourth</option>
              <option value={-1}>last</option>
            </select>
            <select
              value={dayOfWeekInMonth !== undefined ? dayOfWeekInMonth : 1}
              onChange={(e) => {
                setDayOfWeekInMonth(parseInt(e.target.value));
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={0}>Sunday</option>
              <option value={1}>Monday</option>
              <option value={2}>Tuesday</option>
              <option value={3}>Wednesday</option>
              <option value={4}>Thursday</option>
              <option value={5}>Friday</option>
              <option value={6}>Saturday</option>
            </select>
          </label>
        </div>
      )}

      {/* Recur from Completion Date */}
      <div>
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={recurFromCompletion}
            onChange={(e) => setRecurFromCompletion(e.target.checked)}
            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
          />
          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
            Recur from completion date
          </span>
        </label>
        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
        </p>
      </div>

      {/* End Condition */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Ends
        </label>
        <div className="space-y-3">
          {/* Never */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'never'}
              onChange={() => setEndType('never')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
          </label>

          {/* After X occurrences */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'after'}
              onChange={() => setEndType('after')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
            <input
              type="number"
              min="1"
              max="999"
              value={endCount || ''}
              onChange={(e) => {
                setEndType('after');
                setEndCount(Math.max(1, parseInt(e.target.value) || 1));
              }}
              disabled={endType !== 'after'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">occurrences</span>
          </label>

          {/* Until date */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'until'}
              onChange={() => setEndType('until')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">On</span>
            <input
              type="date"
              value={endDate || ''}
              onChange={(e) => {
                setEndType('until');
                setEndDate(e.target.value);
              }}
              disabled={endType !== 'until'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>
        </div>
      </div>

      {/* Advanced Section */}
      <div>
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex items-center gap-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
        >
          {showAdvanced ? (
            <ChevronDown className="w-4 h-4" />
          ) : (
            <ChevronRight className="w-4 h-4" />
          )}
          Advanced
        </button>
        {showAdvanced && (
          <div className="mt-3 space-y-3 pl-6">
            <TemplatePicker
              value={templateId}
              onChange={setTemplateId}
              templates={templates}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
        <p className="text-xs text-text-light-primary dark:text-text-dark-primary">
          {getRecurrenceSummary()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className="flex-1 py-2 px-4 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue/90 transition-colors"
        >
          Save
        </button>
        {onClose && (
          <button
            onClick={onClose}
            className="py-2 px-4 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary text-sm font-medium rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

