import React, { useState, useEffect } from 'react';
import type { Task } from '../types';
import { parseRecurrenceNaturalLanguage } from '../utils/naturalLanguageRecurrence';
import { TemplatePicker } from './TemplatePicker';
import { useTemplateStore } from '../stores/useTemplateStore';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface RecurrencePickerProps {
  value: Task['recurrence'];
  onChange: (recurrence: Task['recurrence']) => void;
  onClose?: () => void;
}

/**
 * RecurrencePicker Component
 * UI for setting up recurring task patterns
 *
 * Features:
 * - Frequency selection (daily, weekly, monthly, yearly)
 * - Interval input (every X days/weeks/months/years)
 * - Day of week picker (for weekly)
 * - Day of month picker (for monthly)
 * - End condition (never, after X occurrences, until date)
 * - Clear visual feedback
 * - Matches Calendar event recurrence UI patterns
 */
export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
  value,
  onChange,
  onClose,
}) => {
  // Local state (synced with value prop)
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    value?.frequency || 'weekly'
  );
  const [interval, setInterval] = useState<number>(value?.interval || 1);
  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
  const [weekOfMonth, setWeekOfMonth] = useState<1 | 2 | 3 | 4 | -1 | undefined>(value?.weekOfMonth);
  const [dayOfWeekInMonth, setDayOfWeekInMonth] = useState<number | undefined>(value?.dayOfWeekInMonth);
  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);

  // Natural language input state
  const [naturalInput, setNaturalInput] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Advanced section toggle
  const [showAdvanced, setShowAdvanced] = useState<boolean>(false);

  // Template store
  const { templates } = useTemplateStore();

  // Sync local state with value prop when it changes
  useEffect(() => {
    if (value) {
      setFrequency(value.frequency);
      setInterval(value.interval);
      setDaysOfWeek(value.daysOfWeek || []);
      setDayOfMonth(value.dayOfMonth);
      setWeekOfMonth(value.weekOfMonth);
      setDayOfWeekInMonth(value.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else {
        setMonthlyMode('day');
      }
      setEndType(value.endType);
      setEndCount(value.endCount);
      setEndDate(value.endDate);
      setRecurFromCompletion(value.recurFromCompletion || false);
      setTemplateId(value.templateId);
    }
  }, [value]);

  // Helper: Parse natural language input
  const handleParseNaturalLanguage = () => {
    if (!naturalInput.trim()) {
      setParseError(null);
      return;
    }

    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    if (parsed) {
      // Auto-fill fields from parsed rule
      setFrequency(parsed.frequency);
      if (parsed.interval !== undefined) setInterval(parsed.interval);
      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else if (parsed.dayOfMonth !== undefined) {
        setMonthlyMode('day');
      }
      setEndType(parsed.endType);
      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
      if (parsed.endDate) setEndDate(parsed.endDate);
      setParseError(null);
    } else {
      setParseError('Could not parse input. Try "every 2 weeks on Monday"');
    }
  };

  // Helper: Toggle day of week selection
  const toggleDayOfWeek = (day: number) => {
    setDaysOfWeek((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    );
  };

  // Helper: Build recurrence summary text
  const getRecurrenceSummary = (): string => {
    let summary = 'Repeats ';

    // Frequency and interval
    if (interval === 1) {
      summary += frequency;
    } else {
      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    }

    // Days of week (for weekly)
    if (frequency === 'weekly' && daysOfWeek.length > 0) {
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
      summary += ` on ${selectedDays}`;
    }

    // Day of month or ordinal pattern (for monthly)
    if (frequency === 'monthly') {
      if (weekOfMonth !== undefined && dayOfWeekInMonth !== undefined) {
        const ordinalStr = { '1': 'first', '2': 'second', '3': 'third', '4': 'fourth', '-1': 'last' }[weekOfMonth.toString()];
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
      } else if (dayOfMonth) {
        summary += ` on day ${dayOfMonth}`;
      }
    }

    // End condition
    if (endType === 'after' && endCount) {
      summary += `, ends after ${endCount} occurrences`;
    } else if (endType === 'until' && endDate) {
      summary += `, ends on ${endDate}`;
    }

    return summary;
  };

  // Save recurrence and call onChange
  const handleSave = () => {
    const recurrence: Task['recurrence'] = {
      frequency,
      interval,
      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
      dayOfMonth: frequency === 'monthly' && monthlyMode === 'day' ? dayOfMonth : undefined,
      weekOfMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? weekOfMonth : undefined,
      dayOfWeekInMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? dayOfWeekInMonth : undefined,
      endType,
      endCount: endType === 'after' ? endCount : undefined,
      endDate: endType === 'until' ? endDate : undefined,
      recurFromCompletion,
      templateId,
    };

    onChange(recurrence);
    if (onClose) onClose();
  };

  // Clear recurrence
  const handleClear = () => {
    onChange(undefined);
    if (onClose) onClose();
  };

  return (
    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
          Set Recurrence
        </h3>
        {value && (
          <button
            onClick={handleClear}
            className="text-xs text-accent-red hover:text-accent-red-hover dark:text-accent-red dark:hover:text-accent-red-hover"
          >
            Clear
          </button>
        )}
      </div>

      {/* Natural Language Input (Quick Setup) */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Quick Setup (optional)
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            value={naturalInput}
            onChange={(e) => setNaturalInput(e.target.value)}
            onBlur={handleParseNaturalLanguage}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleParseNaturalLanguage();
              }
            }}
            placeholder="e.g., every 2 weeks on Monday"
            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          {naturalInput && (
            <button
              onClick={() => {
                setNaturalInput('');
                setParseError(null);
              }}
              className="px-3 py-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Clear
            </button>
          )}
        </div>
        {parseError && (
          <p className="text-xs text-accent-red dark:text-accent-red mt-1">{parseError}</p>
        )}
        {naturalInput && !parseError && (
          <p className="text-xs text-accent-green dark:text-accent-green mt-1">
            ✓ Parsed successfully
          </p>
        )}
      </div>

      {/* Frequency */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Frequency
        </label>
        <select
          value={frequency}
          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
        >
          <option value="daily">Daily</option>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>
      </div>

      {/* Interval */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Repeat every
        </label>
        <div className="flex items-center gap-2">
          <input
            type="number"
            min="1"
            max="999"
            value={interval}
            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
          </span>
        </div>
      </div>

      {/* Days of Week (for weekly) */}
      {frequency === 'weekly' && (
        <div>
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
            Repeat on
          </label>
          <div className="flex gap-2">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
              <button
                key={day}
                onClick={() => toggleDayOfWeek(index)}
                className={`
                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
                  ${
                    daysOfWeek.includes(index)
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-700'
                  }
                `}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Monthly Pattern Selection */}
      {frequency === 'monthly' && (
        <div className="space-y-3">
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
            Repeat on
          </label>

          {/* Option 1: Specific day of month */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'day'}
              onChange={() => setMonthlyMode('day')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Day</span>
            <input
              type="number"
              min="1"
              max="31"
              value={dayOfMonth || ''}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
                setMonthlyMode('day');
              }}
              placeholder="1-31"
              disabled={monthlyMode !== 'day'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>

          {/* Option 2: Ordinal pattern (first Monday, last Friday, etc.) */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'ordinal'}
              onChange={() => setMonthlyMode('ordinal')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">The</span>
            <select
              value={weekOfMonth || 1}
              onChange={(e) => {
                setWeekOfMonth(parseInt(e.target.value) as 1 | 2 | 3 | 4 | -1);
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={1}>first</option>
              <option value={2}>second</option>
              <option value={3}>third</option>
              <option value={4}>fourth</option>
              <option value={-1}>last</option>
            </select>
            <select
              value={dayOfWeekInMonth !== undefined ? dayOfWeekInMonth : 1}
              onChange={(e) => {
                setDayOfWeekInMonth(parseInt(e.target.value));
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={0}>Sunday</option>
              <option value={1}>Monday</option>
              <option value={2}>Tuesday</option>
              <option value={3}>Wednesday</option>
              <option value={4}>Thursday</option>
              <option value={5}>Friday</option>
              <option value={6}>Saturday</option>
            </select>
          </label>
        </div>
      )}

      {/* Recur from Completion Date */}
      <div>
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={recurFromCompletion}
            onChange={(e) => setRecurFromCompletion(e.target.checked)}
            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
          />
          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
            Recur from completion date
          </span>
        </label>
        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
        </p>
      </div>

      {/* End Condition */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Ends
        </label>
        <div className="space-y-3">
          {/* Never */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'never'}
              onChange={() => setEndType('never')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
          </label>

          {/* After X occurrences */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'after'}
              onChange={() => setEndType('after')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
            <input
              type="number"
              min="1"
              max="999"
              value={endCount || ''}
              onChange={(e) => {
                setEndType('after');
                setEndCount(Math.max(1, parseInt(e.target.value) || 1));
              }}
              disabled={endType !== 'after'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">occurrences</span>
          </label>

          {/* Until date */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'until'}
              onChange={() => setEndType('until')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">On</span>
            <input
              type="date"
              value={endDate || ''}
              onChange={(e) => {
                setEndType('until');
                setEndDate(e.target.value);
              }}
              disabled={endType !== 'until'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>
        </div>
      </div>

      {/* Advanced Section */}
      <div>
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex items-center gap-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
        >
          {showAdvanced ? (
            <ChevronDown className="w-4 h-4" />
          ) : (
            <ChevronRight className="w-4 h-4" />
          )}
          Advanced
        </button>
        {showAdvanced && (
          <div className="mt-3 space-y-3 pl-6">
            <TemplatePicker
              value={templateId}
              onChange={setTemplateId}
              templates={templates}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
        <p className="text-xs text-text-light-primary dark:text-text-dark-primary">
          {getRecurrenceSummary()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className="flex-1 py-2 px-4 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue/90 transition-colors"
        >
          Save
        </button>
        {onClose && (
          <button
            onClick={onClose}
            className="py-2 px-4 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary text-sm font-medium rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import type { Task } from '../types';
import { parseRecurrenceNaturalLanguage } from '../utils/naturalLanguageRecurrence';
import { TemplatePicker } from './TemplatePicker';
import { useTemplateStore } from '../stores/useTemplateStore';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface RecurrencePickerProps {
  value: Task['recurrence'];
  onChange: (recurrence: Task['recurrence']) => void;
  onClose?: () => void;
}

/**
 * RecurrencePicker Component
 * UI for setting up recurring task patterns
 *
 * Features:
 * - Frequency selection (daily, weekly, monthly, yearly)
 * - Interval input (every X days/weeks/months/years)
 * - Day of week picker (for weekly)
 * - Day of month picker (for monthly)
 * - End condition (never, after X occurrences, until date)
 * - Clear visual feedback
 * - Matches Calendar event recurrence UI patterns
 */
export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
  value,
  onChange,
  onClose,
}) => {
  // Local state (synced with value prop)
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    value?.frequency || 'weekly'
  );
  const [interval, setInterval] = useState<number>(value?.interval || 1);
  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
  const [weekOfMonth, setWeekOfMonth] = useState<1 | 2 | 3 | 4 | -1 | undefined>(value?.weekOfMonth);
  const [dayOfWeekInMonth, setDayOfWeekInMonth] = useState<number | undefined>(value?.dayOfWeekInMonth);
  const [monthlyMode, setMonthlyMode] = useState<'day' | 'ordinal'>('day');
  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
  const [templateId, setTemplateId] = useState<string | undefined>(value?.templateId);

  // Natural language input state
  const [naturalInput, setNaturalInput] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Advanced section toggle
  const [showAdvanced, setShowAdvanced] = useState<boolean>(false);

  // Template store
  const { templates } = useTemplateStore();

  // Sync local state with value prop when it changes
  useEffect(() => {
    if (value) {
      setFrequency(value.frequency);
      setInterval(value.interval);
      setDaysOfWeek(value.daysOfWeek || []);
      setDayOfMonth(value.dayOfMonth);
      setWeekOfMonth(value.weekOfMonth);
      setDayOfWeekInMonth(value.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (value.weekOfMonth !== undefined && value.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else {
        setMonthlyMode('day');
      }
      setEndType(value.endType);
      setEndCount(value.endCount);
      setEndDate(value.endDate);
      setRecurFromCompletion(value.recurFromCompletion || false);
      setTemplateId(value.templateId);
    }
  }, [value]);

  // Helper: Parse natural language input
  const handleParseNaturalLanguage = () => {
    if (!naturalInput.trim()) {
      setParseError(null);
      return;
    }

    const parsed = parseRecurrenceNaturalLanguage(naturalInput);
    if (parsed) {
      // Auto-fill fields from parsed rule
      setFrequency(parsed.frequency);
      if (parsed.interval !== undefined) setInterval(parsed.interval);
      if (parsed.daysOfWeek) setDaysOfWeek(parsed.daysOfWeek);
      if (parsed.dayOfMonth !== undefined) setDayOfMonth(parsed.dayOfMonth);
      if (parsed.weekOfMonth !== undefined) setWeekOfMonth(parsed.weekOfMonth);
      if (parsed.dayOfWeekInMonth !== undefined) setDayOfWeekInMonth(parsed.dayOfWeekInMonth);
      // Set monthlyMode based on which fields are present
      if (parsed.weekOfMonth !== undefined && parsed.dayOfWeekInMonth !== undefined) {
        setMonthlyMode('ordinal');
      } else if (parsed.dayOfMonth !== undefined) {
        setMonthlyMode('day');
      }
      setEndType(parsed.endType);
      if (parsed.endCount !== undefined) setEndCount(parsed.endCount);
      if (parsed.endDate) setEndDate(parsed.endDate);
      setParseError(null);
    } else {
      setParseError('Could not parse input. Try "every 2 weeks on Monday"');
    }
  };

  // Helper: Toggle day of week selection
  const toggleDayOfWeek = (day: number) => {
    setDaysOfWeek((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    );
  };

  // Helper: Build recurrence summary text
  const getRecurrenceSummary = (): string => {
    let summary = 'Repeats ';

    // Frequency and interval
    if (interval === 1) {
      summary += frequency;
    } else {
      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    }

    // Days of week (for weekly)
    if (frequency === 'weekly' && daysOfWeek.length > 0) {
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
      summary += ` on ${selectedDays}`;
    }

    // Day of month or ordinal pattern (for monthly)
    if (frequency === 'monthly') {
      if (weekOfMonth !== undefined && dayOfWeekInMonth !== undefined) {
        const ordinalStr = { '1': 'first', '2': 'second', '3': 'third', '4': 'fourth', '-1': 'last' }[weekOfMonth.toString()];
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        summary += ` on the ${ordinalStr} ${dayNames[dayOfWeekInMonth]}`;
      } else if (dayOfMonth) {
        summary += ` on day ${dayOfMonth}`;
      }
    }

    // End condition
    if (endType === 'after' && endCount) {
      summary += `, ends after ${endCount} occurrences`;
    } else if (endType === 'until' && endDate) {
      summary += `, ends on ${endDate}`;
    }

    return summary;
  };

  // Save recurrence and call onChange
  const handleSave = () => {
    const recurrence: Task['recurrence'] = {
      frequency,
      interval,
      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
      dayOfMonth: frequency === 'monthly' && monthlyMode === 'day' ? dayOfMonth : undefined,
      weekOfMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? weekOfMonth : undefined,
      dayOfWeekInMonth: frequency === 'monthly' && monthlyMode === 'ordinal' ? dayOfWeekInMonth : undefined,
      endType,
      endCount: endType === 'after' ? endCount : undefined,
      endDate: endType === 'until' ? endDate : undefined,
      recurFromCompletion,
      templateId,
    };

    onChange(recurrence);
    if (onClose) onClose();
  };

  // Clear recurrence
  const handleClear = () => {
    onChange(undefined);
    if (onClose) onClose();
  };

  return (
    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
          Set Recurrence
        </h3>
        {value && (
          <button
            onClick={handleClear}
            className="text-xs text-accent-red hover:text-accent-red-hover dark:text-accent-red dark:hover:text-accent-red-hover"
          >
            Clear
          </button>
        )}
      </div>

      {/* Natural Language Input (Quick Setup) */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Quick Setup (optional)
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            value={naturalInput}
            onChange={(e) => setNaturalInput(e.target.value)}
            onBlur={handleParseNaturalLanguage}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleParseNaturalLanguage();
              }
            }}
            placeholder="e.g., every 2 weeks on Monday"
            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          {naturalInput && (
            <button
              onClick={() => {
                setNaturalInput('');
                setParseError(null);
              }}
              className="px-3 py-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Clear
            </button>
          )}
        </div>
        {parseError && (
          <p className="text-xs text-accent-red dark:text-accent-red mt-1">{parseError}</p>
        )}
        {naturalInput && !parseError && (
          <p className="text-xs text-accent-green dark:text-accent-green mt-1">
            ✓ Parsed successfully
          </p>
        )}
      </div>

      {/* Frequency */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Frequency
        </label>
        <select
          value={frequency}
          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
        >
          <option value="daily">Daily</option>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>
      </div>

      {/* Interval */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Repeat every
        </label>
        <div className="flex items-center gap-2">
          <input
            type="number"
            min="1"
            max="999"
            value={interval}
            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
          />
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
          </span>
        </div>
      </div>

      {/* Days of Week (for weekly) */}
      {frequency === 'weekly' && (
        <div>
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
            Repeat on
          </label>
          <div className="flex gap-2">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
              <button
                key={day}
                onClick={() => toggleDayOfWeek(index)}
                className={`
                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
                  ${
                    daysOfWeek.includes(index)
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                  }
                `}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Monthly Pattern Selection */}
      {frequency === 'monthly' && (
        <div className="space-y-3">
          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
            Repeat on
          </label>

          {/* Option 1: Specific day of month */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'day'}
              onChange={() => setMonthlyMode('day')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Day</span>
            <input
              type="number"
              min="1"
              max="31"
              value={dayOfMonth || ''}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
                setMonthlyMode('day');
              }}
              placeholder="1-31"
              disabled={monthlyMode !== 'day'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>

          {/* Option 2: Ordinal pattern (first Monday, last Friday, etc.) */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="monthly-mode"
              checked={monthlyMode === 'ordinal'}
              onChange={() => setMonthlyMode('ordinal')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">The</span>
            <select
              value={weekOfMonth || 1}
              onChange={(e) => {
                setWeekOfMonth(parseInt(e.target.value) as 1 | 2 | 3 | 4 | -1);
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={1}>first</option>
              <option value={2}>second</option>
              <option value={3}>third</option>
              <option value={4}>fourth</option>
              <option value={-1}>last</option>
            </select>
            <select
              value={dayOfWeekInMonth !== undefined ? dayOfWeekInMonth : 1}
              onChange={(e) => {
                setDayOfWeekInMonth(parseInt(e.target.value));
                setMonthlyMode('ordinal');
              }}
              disabled={monthlyMode !== 'ordinal'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            >
              <option value={0}>Sunday</option>
              <option value={1}>Monday</option>
              <option value={2}>Tuesday</option>
              <option value={3}>Wednesday</option>
              <option value={4}>Thursday</option>
              <option value={5}>Friday</option>
              <option value={6}>Saturday</option>
            </select>
          </label>
        </div>
      )}

      {/* Recur from Completion Date */}
      <div>
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={recurFromCompletion}
            onChange={(e) => setRecurFromCompletion(e.target.checked)}
            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
          />
          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
            Recur from completion date
          </span>
        </label>
        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
        </p>
      </div>

      {/* End Condition */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Ends
        </label>
        <div className="space-y-3">
          {/* Never */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'never'}
              onChange={() => setEndType('never')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
          </label>

          {/* After X occurrences */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'after'}
              onChange={() => setEndType('after')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
            <input
              type="number"
              min="1"
              max="999"
              value={endCount || ''}
              onChange={(e) => {
                setEndType('after');
                setEndCount(Math.max(1, parseInt(e.target.value) || 1));
              }}
              disabled={endType !== 'after'}
              className="w-20 p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">occurrences</span>
          </label>

          {/* Until date */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="endType"
              checked={endType === 'until'}
              onChange={() => setEndType('until')}
              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">On</span>
            <input
              type="date"
              value={endDate || ''}
              onChange={(e) => {
                setEndType('until');
                setEndDate(e.target.value);
              }}
              disabled={endType !== 'until'}
              className="p-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none disabled:opacity-50"
            />
          </label>
        </div>
      </div>

      {/* Advanced Section */}
      <div>
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex items-center gap-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
        >
          {showAdvanced ? (
            <ChevronDown className="w-4 h-4" />
          ) : (
            <ChevronRight className="w-4 h-4" />
          )}
          Advanced
        </button>
        {showAdvanced && (
          <div className="mt-3 space-y-3 pl-6">
            <TemplatePicker
              value={templateId}
              onChange={setTemplateId}
              templates={templates}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
        <p className="text-xs text-text-light-primary dark:text-text-dark-primary">
          {getRecurrenceSummary()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className="flex-1 py-2 px-4 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue/90 transition-colors"
        >
          Save
        </button>
        {onClose && (
          <button
            onClick={onClose}
            className="py-2 px-4 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary text-sm font-medium rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

/**
 * BacklinksPanel Component
 * Displays notes that link TO the current note (backlinks)
 * Uses [[Note Title]] wiki-style linking syntax
 * P1: Also shows unlinked mentions (implicit references)
 */

import { useMemo, useState } from 'react';
import { Link2, ChevronRight, ChevronDown, AlertTriangle, Plus } from 'lucide-react';
import { useNotesStore } from '../stores/useNotesStore';
import { findUnlinkedMentions, findBrokenLinks } from '../utils/backlinks';

interface BacklinksPanelProps {
  noteId: string;
  onNoteClick?: (noteId: string) => void;
}

export function BacklinksPanel({ noteId, onNoteClick }: BacklinksPanelProps) {
  const { getBacklinks, setActiveNote, notes, createNote, convertToWikiLink } = useNotesStore();
  const [showUnlinkedMentions, setShowUnlinkedMentions] = useState(true);
  const [showBrokenLinks, setShowBrokenLinks] = useState(true);

  const currentNote = notes[noteId];

  const backlinks = useMemo(() => {
    return getBacklinks(noteId);
  }, [noteId, getBacklinks]);

  // P1: Find unlinked mentions
  const unlinkedMentions = useMemo(() => {
    if (!currentNote) return [];
    return findUnlinkedMentions(noteId, currentNote.title, notes);
  }, [noteId, currentNote, notes]);

  // P1: Find broken links
  const brokenLinks = useMemo(() => {
    if (!currentNote) return [];
    return findBrokenLinks(currentNote.contentText, notes);
  }, [currentNote, notes]);

  const handleNoteClick = (id: string) => {
    if (onNoteClick) {
      onNoteClick(id);
    } else {
      setActiveNote(id);
    }
  };

  const handleCreateNote = (title: string) => {
    const newNote = createNote({
      title,
      content: '',
      folderId: currentNote?.folderId || null,
    });
    handleNoteClick(newNote.id);
  };

  const handleConvertToLink = (mentionNoteId: string, position: number, targetTitle: string) => {
    convertToWikiLink(mentionNoteId, position, targetTitle);
  };

  const hasBacklinks = backlinks.length > 0;
  const hasUnlinkedMentions = unlinkedMentions.length > 0;
  const hasBrokenLinks = brokenLinks.length > 0;

  if (!hasBacklinks && !hasUnlinkedMentions && !hasBrokenLinks) {
    return (
      <div className="p-4 border-t border-border-light dark:border-border-dark">
        <div className="flex items-center gap-2 text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
          <Link2 className="w-4 h-4" />
          <span className="font-medium">Backlinks</span>
        </div>
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
          No notes link to this note yet. Use [[Note Title]] to create links.
        </p>
      </div>
    );
  }

  return (
    <div className="p-4 border-t border-border-light dark:border-border-dark">
      {/* Linked References */}
      {hasBacklinks && (
        <div className="mb-4">
          <div className="flex items-center gap-2 text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3">
            <Link2 className="w-4 h-4" />
            <span className="font-medium">Linked References</span>
            <span className="px-1.5 py-0.5 text-xs bg-accent-blue/10 text-accent-blue rounded">
              {backlinks.length}
            </span>
          </div>

          <div className="space-y-1">
            {backlinks.map((note) => (
              <button
                key={note.id}
                onClick={() => handleNoteClick(note.id)}
                className="w-full flex items-center gap-2 p-2 text-sm text-left rounded-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors group"
              >
                <span className="text-lg">{note.icon || '📄'}</span>
                <span className="flex-1 truncate text-text-light-primary dark:text-text-dark-primary">
                  {note.title}
                </span>
                <ChevronRight className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary opacity-0 group-hover:opacity-100 transition-opacity" />
              </button>
            ))}
          </div>
        </div>
      )}

      {/* P1: Unlinked Mentions */}
      {hasUnlinkedMentions && (
        <div className={hasBrokenLinks ? 'mb-4' : ''}>
          <button
            onClick={() => setShowUnlinkedMentions(!showUnlinkedMentions)}
            className="w-full flex items-center gap-2 text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3 hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
          >
            {showUnlinkedMentions ? (
              <ChevronDown className="w-4 h-4" />
            ) : (
              <ChevronRight className="w-4 h-4" />
            )}
            <span className="font-medium">Unlinked Mentions</span>
            <span className="px-1.5 py-0.5 text-xs bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark rounded">
              {unlinkedMentions.length}
            </span>
          </button>

          {showUnlinkedMentions && (
            <div className="space-y-2">
              {unlinkedMentions.map((mention, index) => (
                <div
                  key={`${mention.noteId}-${index}`}
                  className="p-2 text-sm rounded-lg bg-surface-light-elevated/50 dark:bg-surface-dark-elevated/50 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors group"
                >
                  <div className="flex items-center gap-2 mb-1">
                    <button
                      onClick={() => handleNoteClick(mention.noteId)}
                      className="flex items-center gap-2 flex-1 min-w-0 text-left"
                    >
                      <span className="text-lg">{notes[mention.noteId]?.icon || '📄'}</span>
                      <span className="flex-1 truncate font-medium text-text-light-primary dark:text-text-dark-primary">
                        {mention.noteTitle}
                      </span>
                      <ChevronRight className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary opacity-0 group-hover:opacity-100 transition-opacity" />
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleConvertToLink(mention.noteId, mention.position, currentNote?.title || '');
                      }}
                      className="flex items-center gap-1 px-2 py-1 text-xs font-medium rounded bg-accent-purple/20 text-accent-purple dark:bg-accent-cyan/20 dark:text-accent-cyan hover:bg-accent-purple/30 dark:hover:bg-accent-cyan/30 transition-colors flex-shrink-0"
                      title="Convert to [[wiki link]]"
                    >
                      <Link2 className="w-3 h-3" />
                      Link
                    </button>
                  </div>
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary ml-8 line-clamp-2">
                    {mention.context}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* P1: Broken Links */}
      {hasBrokenLinks && (
        <div>
          <button
            onClick={() => setShowBrokenLinks(!showBrokenLinks)}
            className="w-full flex items-center gap-2 text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3 hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
          >
            {showBrokenLinks ? (
              <ChevronDown className="w-4 h-4" />
            ) : (
              <ChevronRight className="w-4 h-4" />
            )}
            <AlertTriangle className="w-4 h-4" />
            <span className="font-medium">Broken Links</span>
            <span className="px-1.5 py-0.5 text-xs bg-red-500/10 text-red-500 dark:bg-red-500/20 dark:text-red-400 rounded">
              {brokenLinks.length}
            </span>
          </button>

          {showBrokenLinks && (
            <div className="space-y-2">
              {brokenLinks.map((link, index) => (
                <div
                  key={`${link.title}-${index}`}
                  className="p-2 text-sm rounded-lg bg-red-500/5 dark:bg-red-500/10 border border-red-500/20 dark:border-red-500/30"
                >
                  <div className="flex items-center gap-2 mb-2">
                    <AlertTriangle className="w-4 h-4 text-red-500 dark:text-red-400 flex-shrink-0" />
                    <span className="flex-1 font-medium text-text-light-primary dark:text-text-dark-primary truncate">
                      [[{link.title}]]
                    </span>
                    <button
                      onClick={() => handleCreateNote(link.title)}
                      className="flex items-center gap-1 px-2 py-1 text-xs font-medium rounded bg-accent-purple/20 text-accent-purple dark:bg-accent-cyan/20 dark:text-accent-cyan hover:bg-accent-purple/30 dark:hover:bg-accent-cyan/30 transition-colors flex-shrink-0"
                      title="Create this note"
                    >
                      <Plus className="w-3 h-3" />
                      Create
                    </button>
                  </div>
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary ml-6 line-clamp-2">
                    {link.context}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

